import React, { useState } from "react";
import { XMarkIcon } from "@heroicons/react/24/solid";

export default function AddTask({ closeModal, onTaskAdded }) {
  const [formData, setFormData] = useState({
    title: "",
    dueDate: "",
    priority: "MEDIUM",
    category: "",
    completed: false,
  });

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loadingAI, setLoadingAI] = useState(false); // ✅ AI loading

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === "checkbox" ? checked : value,
    });
  };

  // ✅ 🤖 AI GENERATE FUNCTION
  const handleAIGenerate = async () => {
    setLoadingAI(true);
    setError("");

    try {
      const res = await fetch("http://localhost:8086/tasks/ai-generate", {
        method: "POST"
      });

      const data = await res.json();

      // 🔥 Autofill form
      setFormData({
        ...formData,
        title: data.title || "",
        dueDate: data.dueDate || "",
        priority: data.priority || "MEDIUM",
        category: data.category || "",
      });

    } catch (err) {
      setError("AI generation failed");
    } finally {
      setLoadingAI(false);
    }
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    if (!formData.title || !formData.dueDate) {
      setError("Please fill required fields");
      return;
    }

    try {
      const res = await fetch("http://localhost:8086/tasks", {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify({
          ...formData,
          autoGenerated: false,
          suggestionSource: "AI",
          notified: false
        })
      });

      if (res.ok) {
        setSuccess("Task added successfully!");

        if (onTaskAdded) onTaskAdded();

        setTimeout(() => closeModal(), 1000);
      }
    } catch (err) {
      setError("Server error");
    }
  };

  return (
    <div className="w-[420px] p-8 rounded-2xl backdrop-blur-xl bg-white/20 border border-white/30 shadow-2xl relative">

      {/* Close */}
      <button onClick={closeModal} className="absolute top-3 right-3 text-white">
        <XMarkIcon className="w-6 h-6" />
      </button>

      <h2 className="text-2xl font-bold text-white text-center mb-4">
        Add Task
      </h2>

      {/* ✅ 🤖 AI BUTTON */}
      <button
        type="button"
        onClick={handleAIGenerate}
        className="w-full mb-4 py-2 rounded-lg bg-purple-500/70 hover:bg-purple-600 text-white font-semibold transition"
      >
        {loadingAI ? "Analyzing..." : "🤖 Generate Task"}
      </button>

      {success && <p className="text-green-300 text-center mb-2">{success}</p>}
      {error && <p className="text-red-300 text-center mb-2">{error}</p>}

      <form onSubmit={handleAdd} className="space-y-4">

        <input
          type="text"
          name="title"
          placeholder="Task Title"
          value={formData.title}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg bg-white/30 text-white"
        />

        <input
          type="date"
          name="dueDate"
          value={formData.dueDate}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg bg-white/30 text-white"
        />

        <select
          name="priority"
          value={formData.priority}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg bg-white/30 text-white"
        >
          <option value="LOW" className="text-black">Low</option>
          <option value="MEDIUM" className="text-black">Medium</option>
          <option value="HIGH" className="text-black">High</option>
        </select>

        <input
          type="text"
          name="category"
          placeholder="Category"
          value={formData.category}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg bg-white/30 text-white"
        />

        <button
          type="submit"
          className="w-full py-2 rounded-lg bg-white/30 hover:bg-white/40 text-white font-semibold"
        >
          Add Task
        </button>
      </form>
    </div>
  );
}
